import { memo, PropsWithChildren, useContext, useEffect, useMemo, useState } from 'react';
import axios from 'axios';

import { ConfigContext } from '../../contexts/configContext';

export const WakeServerComponent = memo((props: PropsWithChildren<unknown>) => {
  const { apiUrl } = useContext(ConfigContext);

  const [isLoading, setLoading] = useState(true);
  const [tryAgain, setTryAgain] = useState(false);
  const [firstLoad, setFirstLoad] = useState(true);

  useEffect(() => {
    if (apiUrl.length === 0) {
      console.error('Missing api url');
      return;
    }

    const runAsync = async () => {
      try {
        const response = await axios.get('/api/ready', {
          baseURL: apiUrl
        });
        if (response.status === 200) {
          setLoading(false);
        } else {
          setFirstLoad(false);
          setTryAgain(!tryAgain);
        }
      } catch {
        setFirstLoad(false);
        setTryAgain(!tryAgain);
      }
    };
    // first time - check is the server is up
    isLoading && firstLoad && runAsync();
    // is not the first time - wait 2s to check again if the server is up
    isLoading && !firstLoad && setTimeout(() => runAsync(), 2000);
  }, [apiUrl, firstLoad, tryAgain]);

  const loadingElement = useMemo(() => {
    // only show the loading by the second time
    // this will avoid show the loading every reload
    if (firstLoad) {
      return <></>;
    }
    return (
      <>
        <div className="d-flex justify-content-center m-4">
          <div className="spinner-border" role="status">
            <span className="visually-hidden">Loading...</span>
          </div>
        </div>
        <div className="d-flex justify-content-center">
          <p>server is sleeping, hang tight.</p>
        </div>
      </>
    );
  }, []);

  return <>{isLoading ? loadingElement : props.children}</>;
});
